#include <iostream>

int main() {
    int n;
    std::cin >> n;
    int arr[1000];
    for (int i = 0; i < n; i++) {
        std::cin >> arr[i];
    }
    std::cout << arr[0];
    for (int i = 1; i < n; i++) {
        bool duplicate = false;
        for (int j = 0; j < i; j++) {
            if (arr[i] == arr[j]) {
                duplicate = true;
                break;
            }
        }
        if (!duplicate) {
            std::cout << " " << arr[i];
        }
    }
    std::cout << std::endl;
    return 0;
}
